```julia
julia> using JuMP, Ipopt

julia> begin
           model = Model(Ipopt.Optimizer)
           set_silent(model)
           @variable(model, x == 1.5)
           @variable(model, z)
           @objective(model, Min, z)
           @constraint(model, [x, 1, z] in MOI.ExponentialCone())
           optimize!(model)
           @assert is_solved_and_feasible(model)
           value(z), exp(1.5)
       end
